mapper.update:
UPDATE d_user_refresh_tokens
SET expires_at = #{expiresAt},
    revoked_at = #{revokedAt}
WHERE id = #{id}

UPDATE d_user_refresh_tokens
SET revoked_at = #{revokedAt}
WHERE id = #{id}
  AND revoked_at IS NULL
  AND expires_at > #{revokedAt}

mapper.delete:
DELETE FROM d_user_refresh_tokens
WHERE expires_at < #{deleteBefore}
   OR (revoked_at IS NOT NULL AND revoked_at < #{deleteBefore})
